			ID:          parseUUID(agentID),
			WorkspaceID: parseUUID(workspaceID),
		})
		if err != nil || agent.ArchivedAt.Valid || !agent.RuntimeID.Valid {
			continue
		}
		return &agent
	}
	return nil
}

