export default function SkillsPage() {
  const isLoading = useAuthStore((s) => s.isLoading);
  const skills = useWorkspaceStore((s) => s.skills);
  const refreshSkills = useWorkspaceStore((s) => s.refreshSkills);
  const upsertSkill = useWorkspaceStore((s) => s.upsertSkill);
  const removeSkill = useWorkspaceStore((s) => s.removeSkill);
  const isMobile = useIsMobile();
  const [selectedId, setSelectedId] = useQueryParamSelection("skill");
  const [showCreate, setShowCreate] = useState(false);
  const { defaultLayout, onLayoutChanged } = useDefaultLayout({
    id: "multica_skills_layout",
  });

  useEffect(() => {
    if (selectedId && !skills.some((skill) => skill.id === selectedId)) {
      setSelectedId("", { replace: true });
    }
  }, [skills, selectedId]);

  const handleCreate = async (data: CreateSkillRequest) => {
    const skill = await api.createSkill(data);
    upsertSkill(skill);
    setSelectedId(skill.id);
    toast.success("Skill created");
  };

  const handleImport = async (url: string) => {
    const skill = await api.importSkill({ url });
    upsertSkill(skill);
    setSelectedId(skill.id);
    toast.success("Skill imported");
  };

  const handleUpdate = async (id: string, data: UpdateSkillRequest) => {
    try {
      const updated = await api.updateSkill(id, data);
      upsertSkill(updated);
      toast.success("Skill saved");
    } catch (e) {
      toast.error(e instanceof Error ? e.message : "Failed to save skill");
      throw e;
    }
  };

  const handleDelete = async (id: string) => {
    try {
      await api.deleteSkill(id);
      if (selectedId === id) {
        const remaining = skills.filter((s) => s.id !== id);
        setSelectedId(remaining[0]?.id ?? "");
      }
      removeSkill(id);
      toast.success("Skill deleted");
    } catch (e) {
      toast.error(e instanceof Error ? e.message : "Failed to delete skill");
    }
  };

  const effectiveSelectedId = selectedId || (!isMobile ? skills[0]?.id ?? "" : "");
  const selected = skills.find((s) => s.id === effectiveSelectedId) ?? null;

  if (isLoading) {
    return (
      <div className="flex flex-1 min-h-0">
        {/* List skeleton */}
        <div className="w-72 border-r">
          <div className="flex h-12 items-center justify-between border-b px-4">
            <Skeleton className="h-4 w-16" />
            <Skeleton className="h-6 w-6 rounded" />
          </div>
          <div className="divide-y">
            {Array.from({ length: 3 }).map((_, i) => (
              <div key={i} className="flex items-center gap-3 px-4 py-3">
                <Skeleton className="h-8 w-8 rounded-lg" />
                <div className="flex-1 space-y-1.5">
                  <Skeleton className="h-4 w-28" />
                  <Skeleton className="h-3 w-40" />
                </div>
              </div>
            ))}
          </div>
        </div>
        {/* Detail skeleton */}
        <div className="flex-1 flex flex-col">
          <div className="flex items-center gap-3 border-b px-4 py-3">
            <Skeleton className="h-8 w-8 rounded-lg" />
            <Skeleton className="h-8 w-40" />
            <Skeleton className="h-8 w-56" />
          </div>
          <div className="flex flex-1 min-h-0">
            <div className="w-48 border-r p-3 space-y-2">
              <Skeleton className="h-4 w-full" />
              <Skeleton className="h-4 w-3/4" />
            </div>
            <div className="flex-1 p-4 space-y-2">
              <Skeleton className="h-4 w-full" />
              <Skeleton className="h-4 w-5/6" />
              <Skeleton className="h-4 w-2/3" />
            </div>
          </div>
        </div>
      </div>
    );
  }

  const renderList = (showBorder: boolean) => (
    <div className={`h-full overflow-y-auto ${showBorder ? "border-r" : ""}`}>
      <div className="flex h-12 items-center justify-between border-b px-4">
        <h1 className="text-sm font-semibold">Skills</h1>
        <Tooltip>
          <TooltipTrigger
            render={
              <Button
                variant="ghost"
                size="icon-xs"
                onClick={() => setShowCreate(true)}
              >
                <Plus className="h-4 w-4 text-muted-foreground" />
              </Button>
            }
          />
          <TooltipContent side="bottom">Create skill</TooltipContent>
        </Tooltip>
      </div>
      {skills.length === 0 ? (
        <div className="flex flex-col items-center justify-center px-4 py-12">
          <Sparkles className="h-8 w-8 text-muted-foreground/40" />
          <p className="mt-3 text-sm text-muted-foreground">No skills yet</p>
          <p className="mt-1 text-center text-xs text-muted-foreground">
            Skills define reusable instructions for agents.
          </p>
          <Button
            onClick={() => setShowCreate(true)}
            size="xs"
            className="mt-3"
          >
            <Plus className="h-3 w-3" />
            Create Skill
          </Button>
        </div>
      ) : (
        <div className="divide-y">
          {skills.map((skill) => (
            <SkillListItem
              key={skill.id}
              skill={skill}
              isSelected={skill.id === effectiveSelectedId}
              onClick={() => setSelectedId(skill.id)}
            />
          ))}
        </div>
      )}
    </div>
  );

  const renderDetail = (withBack: boolean) => (
    <div className="h-full overflow-hidden">
      {selected ? (
        <SkillDetail
          key={selected.id}
          skill={selected}
          onUpdate={handleUpdate}
          onDelete={handleDelete}
          onBack={withBack ? () => setSelectedId("") : undefined}
        />
      ) : (
        <div className="flex h-full flex-col items-center justify-center text-muted-foreground">
          <Sparkles className="h-10 w-10 text-muted-foreground/30" />
          <p className="mt-3 text-sm">Select a skill to view details</p>
          <Button
            onClick={() => setShowCreate(true)}
            size="xs"
            className="mt-3"
          >
            <Plus className="h-3 w-3" />
            Create Skill
          </Button>
        </div>
      )}
    </div>
  );

  return (
    <>
      {isMobile ? (
        selected ? renderDetail(true) : renderList(false)
      ) : (
        <ResizablePanelGroup
          orientation="horizontal"
          className="flex-1 min-h-0"
          defaultLayout={defaultLayout}
          onLayoutChanged={onLayoutChanged}
        >
          <ResizablePanel id="list" defaultSize={280} minSize={240} maxSize={400} groupResizeBehavior="preserve-pixel-size">
            {renderList(true)}

