func (h *Handler) commentTargetsActivePlanThread(ctx context.Context, issue db.Issue, comment db.Comment, parentComment *db.Comment) bool {
	stage := service.NormalizeExecutionStage(issue.ExecutionStage)
	if stage != service.ExecutionStagePlanning && stage != service.ExecutionStagePlanReady {
		return false
	}
	if !comment.ParentID.Valid {
		return false
	}

	latestPlan := h.latestPlanPayload(ctx, issue.ID)
	if latestPlan == nil {
		return false
	}
	rootID := strings.TrimSpace(latestPlan.PlanThreadRootID)
	if rootID == "" {
		rootID = strings.TrimSpace(latestPlan.PlanCommentID)
	}
	if rootID == "" {
		return false
	}

	parentID := uuidToString(comment.ParentID)
	if parentID == rootID {
		return true
	}
	if parentComment != nil {
		if uuidToString(parentComment.ID) == rootID {
			return true
		}
		if parentComment.ParentID.Valid && uuidToString(parentComment.ParentID) == rootID {
			return true
		}
	}
	return false
}

// commentMentionsOthersButNotAssignee returns true if the comment @mentions
// anyone but does NOT @mention the issue's assignee agent. This is used to
// suppress the on_comment trigger when the user is directing their comment at
// someone else (e.g. sharing results with a colleague, asking another agent).
// @all is treated as a broadcast — it suppresses the trigger because the user
// is announcing to everyone, not specifically requesting work from the agent.
func (h *Handler) commentMentionsOthersButNotAssignee(content string, issue db.Issue) bool {
	mentions := util.ParseMentions(content)
	// Filter out issue mentions — they are cross-references, not @people.
	filtered := mentions[:0]
	for _, m := range mentions {
		if m.Type != "issue" {
			filtered = append(filtered, m)
		}
	}
	mentions = filtered
	if len(mentions) == 0 {
		return false // No mentions (or only issue refs) — normal on_comment behavior
